A simple 2D Axis-Aligned Bounding Box overlap test:

```cpp
struct FAABB2D {
    float MinX, MinY;
    float MaxX, MaxY;
};

bool CheckAABBOverlap(const FAABB2D& BoxA, const FAABB2D& BoxB) {
    // If any gap exists, they cannot overlap
    if (BoxA.MaxX < BoxB.MinX || BoxB.MaxX < BoxA.MinX) return false;
    if (BoxA.MaxY < BoxB.MinY || BoxB.MaxY < BoxA.MinY) return false;

    return true;
}
```
